import { HttpErrorResponse } from "@angular/common/http";
import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { catchError } from "rxjs/operators";
import { AlertService } from "src/app/core/services/alert.service";
import { AgreementService } from "src/app/core/services/overdraft/agreement.service";
import { ReferencesService } from "src/app/core/services/references.service";
import { AgreementInfo } from "src/app/views/Models/Loan/AgreementInfo";
import { UpdateAgreementRequest } from "src/app/views/Models/Overdraft/Agreement/UpdateAgreement";
import { SearchResult } from "src/app/views/Models/References/SearchResult";
import { StaticRef } from "src/app/views/Models/References/StaticRef";

enum State {
  SEARCHING,
  LIST,
  DETAIL,
}

@Component({
  selector: "app-manage-agreement",
  templateUrl: "./manage-agreement.page.html",
  styleUrls: ["./manage-agreement.page.scss"],
})
export class ManageAgreementPage implements OnInit {
  constructor(
    private agreementService: AgreementService,
    private referencesService: ReferencesService,
    private formBuilder: FormBuilder,
    private alertService: AlertService
  ) {}

  private readonly EXCLUDED_STATUSES = ["0", "2"];

  State = State;
  currentViewState: State = State.SEARCHING;
  showLoader: boolean = false;
  selectedClient: SearchResult;
  agreements: AgreementInfo[] = [];
  agreement: AgreementInfo;
  agreementStatusList: StaticRef[] = [];
  manageAgreementForm: FormGroup = this.formBuilder.group({
    agreementStatus: [null, [Validators.required]],
  });

  ngOnInit() {
    this.retrieveAgreementsStatus();
  }

  retrieveAgreementsStatus() {
    this.referencesService
      .getOverDraftAgreementStatus()
      .pipe(
        catchError((error) => {
          this.handleError(error);
          return [];
        })
      )
      .subscribe(
        (statuses) =>
          (this.agreementStatusList = statuses.filter(
            (stat) => !this.EXCLUDED_STATUSES.includes(stat.ref_code)
          ))
      );
  }

  clientSelected(event: SearchResult) {
    this.selectedClient = event;
    if (event.client_key == null) return;
    this.agreementService
      .getAgreementsByClientKey(event.client_key.toString(), 1)
      .subscribe((response) => {
        if (response.length === 0) {
          return this.alertService.showAlertError(
            "لا يوجد حساب لهذا العميل",
            false
          );
        }
        this.agreements = response;
        this.currentViewState = State.LIST;
      });
  }

  onSelectAgreement(agreement: AgreementInfo) {
    this.agreement = agreement;
    this.currentViewState = State.DETAIL;

    this.manageAgreementForm.patchValue({
      agreementStatus: agreement.agr_status,
    });
  }

  async saveAgreement() {
    if (!this.manageAgreementForm.valid) return;
    if (!(await this.alertService.SaveAlert())) return;

    try {
      this.showLoader = true;
      const request: UpdateAgreementRequest = {
        agreementKey: this.agreement.agreement_key,
        agreementStatus: this.manageAgreementForm.get("agreementStatus").value,
        agreementUuc: this.agreement.agreement_uuc,
      };

      await this.agreementService.updateAgreement(request).toPromise();

      this.alertService.showAlertConfirm("لقد تم الحفظ بنجاح", true);
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }

  backButton() {
    if (this.currentViewState === State.LIST) {
      this.agreements = [];
      this.currentViewState = State.SEARCHING;
    } else if (this.currentViewState === State.DETAIL) {
      this.agreement = null;
      this.currentViewState = State.LIST;
    }
  }

  private handleError(error: unknown) {
    const errorMessage =
      error instanceof HttpErrorResponse
        ? JSON.stringify(error.error)
        : error instanceof Error
        ? error.message
        : String(error);

    this.alertService.showAlertError(errorMessage, false);
    console.error("Error:", error);
  }
}
